import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as d,c as e,a as r}from"./app-543248b1.js";const o={},c=r('<h1 id="vim的基本使用" tabindex="-1"><a class="header-anchor" href="#vim的基本使用" aria-hidden="true">#</a> Vim的基本使用</h1><p>常用命令：<br> 查找字符串，例如搜索user：<code>/user</code>，此时关键字被高亮，按n可以找下一个匹配，N为上一个</p><table><thead><tr><th>用法</th><th>键位</th></tr></thead><tbody><tr><td>移到单词开头</td><td>b</td></tr><tr><td>移到单词结尾</td><td>e</td></tr><tr><td>撤回</td><td>u</td></tr><tr><td>取消撤回</td><td>control+r</td></tr><tr><td>删除一行</td><td>dd</td></tr><tr><td>向后删一个单词</td><td>de</td></tr><tr><td>不退出vim执行shell</td><td><code>:shell</code>,然后exit返回vim</td></tr><tr><td>搜索,例如user</td><td><code>/user</code>，然后n往下找,N往上</td></tr><tr><td>取消搜索高亮</td><td><code>:noh</code></td></tr><tr><td>移动到行尾</td><td><code>^</code>也就是<code>shift+6 </code></td></tr><tr><td>移动到行首</td><td><code>$</code>,也就是<code>shift+4</code></td></tr><tr><td>删除到结尾</td><td><code>d$</code></td></tr><tr><td>替换一个字母</td><td>r</td></tr><tr><td></td><td></td></tr></tbody></table>',3),a=[c];function s(i,h){return d(),e("div",null,a)}const l=t(o,[["render",s],["__file","Vim使用.html.vue"]]);export{l as default};
